VALUES
  ('judicial-d35ec6db-moex-00257', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲開車載其好友乙、丙、丁出遊，旅途上遭一輛由 X駕駛之轎車撞擊，
此車禍肇因於 X闖紅燈所致，甲之車上四人並因此受到輕重傷。嗣後，
乙、丙、丁選定甲作為原告，向法院起訴請求 X賠償損害。試說明：
若丁現年十七歲且未婚，其自為選定當事人之選定行為，於甲提起訴
訟後，丁之法定代理人再承認該選定行為，該選定行為及承認之效力
如何？（12分）
若訴訟中甲死亡，如何進行後續程序？若訴訟中丁死亡（其母戊為唯
一繼承人），對於程序有何影響？ （13分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "01aa4013d788", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00258', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲主張乙對甲負有新臺幣（以下同）100萬元之借款債務尚未清償，甲遂
起訴請求乙給付 100 萬元，第一審法院判決甲請求 60 萬元部分為有理
由，並駁回甲其餘40萬元部分之訴。第一審判決正本於民國111年（以
下同）6月15日依法送達至甲的住所，於6月18日依法寄存送達至乙住
所地之警察機關，乙於6月30日始至該警察機關領取。甲、乙均未提起
上訴，試說明本件當事人之上訴期間何時屆滿及判決何時確定。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "01aa4013d788", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00259', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '公務員甲因涉嫌虛報差旅交通費，檢察官認為甲涉犯貪污，以貪污治罪
條例第 5 條第 1項第 2款之「利用職務機會詐取財物罪」起訴甲。一審
法院審理時皆以該罪名為前提進行證據調查與辯論，然而評議時卻認為
甲之行為並不該當「利用職務上機會」，於是在判決中變更起訴法條為刑
法第 339 條之普通詐欺罪。又法院認為甲明知沒有出差之事實，卻使掌
管差勤記錄之其他公務員登載不實之差勤記錄，並持之請領差旅費用，
應成立刑法第 214 條使公務員登載不實罪、同法第 216條行使不實公文
書之罪，三罪具實質上一罪關係（吸收關係），僅論較重之詐欺罪，其餘
二罪在判決理由中交代。試問一審判決是否合法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "01aa4013d788", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00260', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-2909f946', 'sub-judicial-d35ec6db-03', NULL, 'essay', '甲男涉嫌對乙女強制性交，檢察官基於被害人乙對甲之指述、乙之親友
丙於警詢時之陳述：「某日我與乙去喝咖啡，乙自廁所返回座位時，一
反常情，表情呆滯，我察覺有異，幾經詢問後，乙在激動、哭泣之情緒
下，說出前天於補習班遭甲性侵害」等兩項證據，以犯強制性交罪為由
提起公訴。一審法院審理時，丙因留學滯留國外而傳喚不到。問丙之陳
述有無證據能力？法院能否將丙之陳述作為認定甲成立犯罪之證據？
（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "01aa4013d788", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0408", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法概要與刑事訴訟法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00261', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'essay', '甲乙兩人結褵數載，鶼鰈情深。乙平日在家操持家務，甲趁著數日連假，
開著愛車載乙遊歷花東。不料途中遭酒駕的丙衝撞（酒精濃度超過每公
升零點一五毫克），甲不僅愛車全毀，且全身骨折、五臟六腑俱受重創，
乙則奇蹟似地毫髮無傷。甲於住院治療期間，頻繁接受手術，加上頓時
失去收入及須支付龐大醫療費用等壓力，痛苦萬分，所幸尚有乙日夜相
伴照料。惟甲在治療數月之後，仍傷重不治死亡。乙悲痛地為甲辦理後
事。乙係甲唯一的繼承人。試問：乙對丙有何權利可資主張？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00262', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'essay', '甲與乙、丙共有A地，三人應有部分登記各三分之一。某日，甲乙不顧
丙之反對將 A地以低於市場行情的租金出租且交付於丁使用。試問：
丙得否請求丁將 A地返還於全體共有人？若不得，丙有何其他救濟手
段可資主張？（10 分）
若丙無奈之餘，向好友戊傾訴此事，經戊慫恿，丙將其應有部分讓與
戊。試問：戊得否請求丁將 A地返還於全體共有人？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00263', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '財團法人之董事，代表法人向他人借款，嗣後何人應就此一借款債務，負清償責任？', '["法人單獨負責", "董事單獨負責", "法人、董事個別負責", "法人、董事均不須負責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00264', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '關於甲主張其與乙通謀而為之虛偽意思表示無效，及丁之債權人丙依民法第244條向法院聲請撤 銷丁對戊無償贈與其金錢之行為之情形，下列敘述，何者正確？', '["甲、丁之意思表示均為有效意思表示", "甲僅得於與乙所為者係有償行為之情形，始得主張無效", "甲乙間之法律行為不限於財產行為，丁戊間之法律行為則限於財產行為", "即使丁對戊之贈與未害及丙對丁之債權，丙仍得聲請法院撤銷該贈與行為 20420 20520"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00265', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '甲現年 17 歲，假造其父母之同意函，向經營機車行之乙購買機車 1 輛。甲乙間買賣契約之效力 如何？', '["有效但得撤銷", "效力未定", "無效", "有效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00266', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-a7c7609b', 'sub-judicial-d35ec6db-04', NULL, 'single_choice', '依民法規定，關於旅客之行李，下列敘述，何者錯誤？', '["運送人對於旅客所交託之行李，如未另收運費，不適用物品運送之規定", "運送人對於旅客所未交託之行李，如因自己之過失致有毀損者，仍負責任", "運送人對於旅客所未交託之行李，如因其受僱人之過失致有毀損者，仍負責任", "運送人對於旅客所未交託之行李，如因其他旅客之過失致有喪失者，不負責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:13+00:00", "source_pdf_sha1": "9782819ab81e", "answer_pdf_sha1": "ce63d38ef027", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
